/**
 * AgregarSubascoins — Bloque de Concorde (Voyager DS)
 *
 * Pantalla «Agregar SubasCoins»: Header logueado + un área gris placeholder
 * (mismo gris que los banners de los demás bloques) que ocupa el resto del alto.
 *
 * Bloque = composición de componentes existentes (reusa el bloque Header).
 */

import type { CSSProperties, JSX } from "react";
import AppHeader from "@/concorde/bloques/header/desktop/Header";
import { HEADER_HEIGHT } from "@/concorde/bloques/header/desktop/dimensions";
import SubasCoinsCard from "./SubasCoinsCard";
import { AGREGARSUBASCOINS_WIDTH, AGREGARSUBASCOINS_HEIGHT } from "./dimensions";

export { AGREGARSUBASCOINS_WIDTH, AGREGARSUBASCOINS_HEIGHT } from "./dimensions";

export interface AgregarSubascoinsProps {
  /** Usuario logueado — alimenta el CTA del header. */
  username?: string;
  className?: string;
}

// Banner placeholder gris 766×120 (igual estilo que los banners de Homepage / Zona).
const BANNER_PLACEHOLDER: CSSProperties = {
  width: 766,
  height: 120,
  borderRadius: 8,
  background: "#E9EAEC",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: 13,
  fontWeight: 600,
  letterSpacing: "0.06em",
  color: "#9AA1AC",
};

export default function AgregarSubascoins({ username = "ZAEX5G", className = "" }: AgregarSubascoinsProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="agregar-subascoins"
      style={{
        width: AGREGARSUBASCOINS_WIDTH,
        minHeight: AGREGARSUBASCOINS_HEIGHT,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        overflow: "hidden",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <AppHeader width={AGREGARSUBASCOINS_WIDTH} username={username} />

      {/* Área blanca: columna de 766 (16px a cada lado = 798), gap 16 entre secciones */}
      <div style={{ flex: 1, minHeight: AGREGARSUBASCOINS_HEIGHT - HEADER_HEIGHT, padding: "24px 16px", display: "flex", justifyContent: "center" }}>
        <div style={{ width: 766, display: "flex", flexDirection: "column", gap: 16 }}>
          {/* Banner superior 766×120 */}
          <div data-slot="banner" style={BANNER_PLACEHOLDER}>
            BANNER
          </div>

          {/* Card «Adquiere SubasCoins» 766×437 */}
          <SubasCoinsCard />

          {/* Banner Centro de ayuda 766×100 */}
          <div data-slot="help-banner" style={{ ...BANNER_PLACEHOLDER, height: 100 }}>
            CENTRO DE AYUDA
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Dimensiones del bloque Agregar Subascoins — módulo PLANO (sin "use client")
 * para que los Server Components (catálogo /blocks, página del bloque) puedan
 * importar estas constantes sin que se evalúen a undefined → NaN en los cálculos
 * de escala.
 *
 * Agregar Subascoins = Header (vault, 64) + área gris (placeholder) hasta 785 alto.
 */

export const AGREGARSUBASCOINS_WIDTH = 798;
// 64 (header) + 24 + [120 banner + 16 + 437 card + 16 + 100 help] + 24
export const AGREGARSUBASCOINS_HEIGHT = 801;

"use client";

/**
 * SubasCoinsCard — card 766×437 del bloque «Agregar Subascoins».
 *
 * 2 columnas:
 *   · Izquierda → título + SubasCoinsInfoCard (beneficios) + nota del valor >S<
 *   · Derecha   → AmountOptionGroup (montos 30/50/80/130 + monto personalizado) + botón «Sigamos»
 */

import { useState } from "react";
import type { JSX } from "react";
import AmountOptionGroup, { type AmountSelection } from "@/concorde/components/AmountOptionGroup";
import Button from "@/concorde/components/Button";
import SubasCoinsInfoCard from "./SubasCoinsInfoCard";

export const SUBASCOINSCARD_WIDTH = 766;
export const SUBASCOINSCARD_HEIGHT = 437;

export interface SubasCoinsCardProps {
  className?: string;
}

export default function SubasCoinsCard({ className = "" }: SubasCoinsCardProps): JSX.Element {
  const [sel, setSel] = useState<AmountSelection>(2); // ">S< 80" preseleccionado

  return (
    <div
      className={className}
      data-slot="subascoins-card"
      style={{
        boxSizing: "border-box",
        width: SUBASCOINSCARD_WIDTH,
        minHeight: SUBASCOINSCARD_HEIGHT,
        background: "#ffffff",
        borderRadius: 16,
        boxShadow: "0 0 16px 4px rgba(0,0,0,0.08)",
        padding: 32,
        display: "flex",
        gap: 32,
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      {/* ── Columna izquierda ── */}
      <div style={{ flex: "1 1 0", minWidth: 0, display: "flex", flexDirection: "column", gap: 20 }}>
        <h2
          style={{
            margin: 0,
            fontSize: 20,
            lineHeight: "28px",
            fontWeight: 800,
            letterSpacing: 0,
            // VYGradientPurple: #5F3ED8 → #340091 → #140046
            backgroundImage: "linear-gradient(135deg, #5F3ED8 0%, #340091 55%, #140046 100%)",
            WebkitBackgroundClip: "text",
            backgroundClip: "text",
            color: "transparent",
            WebkitTextFillColor: "transparent",
          }}
        >
          ¡Adquiere{" "}
          <span
            style={{
              // VYGradientOrange1: #FF9639 → #EF852E → #BE3D00
              backgroundImage: "linear-gradient(135deg, #FF9639 0%, #EF852E 50%, #BE3D00 100%)",
              WebkitBackgroundClip: "text",
              backgroundClip: "text",
              color: "transparent",
              WebkitTextFillColor: "transparent",
            }}
          >
            SubasCoins
          </span>{" "}
          y disfruta de sus beneficios!
        </h2>

        <SubasCoinsInfoCard />

        <p style={{ margin: 0, fontSize: 13, fontWeight: 600, color: "#ED8936" }}>
          El valor de <strong>{">S<"} 1</strong> es equivalente a US$ 1 (un Dólar Americano).
        </p>
      </div>

      {/* ── Columna derecha ── */}
      <div style={{ flex: "0 0 254px", display: "flex", flexDirection: "column", gap: 20 }}>
        <AmountOptionGroup
          amounts={["30", "50", "80", "130"]}
          allowCustom
          customPlaceholder="210"
          value={sel}
          onChange={setSel}
        />
        <div style={{ display: "flex", justifyContent: "center" }}>
          <Button variant="primary" style={{ width: 200 }}>Sigamos</Button>
        </div>
      </div>
    </div>
  );
}

"use client";

/**
 * SubasCoinsInfoCard — sub-componente del bloque «Agregar Subascoins».
 *
 * Card morado «Selecciona los SubasCoins que deseas adquirir» con:
 *   · header gradiente (#8460E5 → #3B1782) + ícono $ circular gradiente
 *   · lista de beneficios (pills con bullet gradiente naranja→morado)
 * Recreado en HTML/CSS (no SVG) para que sea editable y escalable.
 */

import type { JSX } from "react";

const STYLE_ID = "concorde-subascoinsinfocard-styles";

const STYLES = `
.scinfo {
  box-sizing: border-box;
  width: 392px;
  max-width: 100%;
  border-radius: 16px;
  background: #ffffff;
  box-shadow: 0 0 16px 4px rgba(0,0,0,0.10);
  overflow: hidden;
  font-family: var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif);
}
.scinfo__head {
  box-sizing: border-box;
  position: relative;
  height: 88px;
  padding: 0 24px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  background: linear-gradient(115deg, #8460E5 0%, #3B1782 100%);
  overflow: hidden;
}
.scinfo__eyebrow { font-size: 13px; font-weight: 500; color: rgba(255,255,255,0.85); margin: 0; }
.scinfo__title { font-size: 22px; font-weight: 800; letter-spacing: -0.01em; color: #ffffff; margin: 2px 0 0; }
.scinfo__sub { font-size: 13px; font-weight: 500; color: rgba(255,255,255,0.85); margin: 2px 0 0; }
.scinfo__coin {
  position: absolute;
  top: 20px;
  right: 24px;
  width: 48px;
  height: 48px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ED8936 0%, #ED8936 40%, #8460E5 100%);
  border: 1px solid rgba(255,255,255,0.6);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #ffffff;
  font-size: 22px;
  font-weight: 800;
  box-shadow: 0 2px 6px rgba(237,137,54,0.3);
}
.scinfo__body {
  box-sizing: border-box;
  height: 157px;
  padding: 20px 24px 24px;
}
.scinfo__benefitslabel {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #99A1AF;
  margin: 0 0 14px;
}
.scinfo__pill {
  box-sizing: border-box;
  display: flex;
  align-items: center;
  gap: 12px;
  width: 100%;
  height: 40px;
  padding: 0 16px;
  border-radius: 20px;
  border: 1px solid transparent;
  background-image: linear-gradient(#ffffff, #ffffff), linear-gradient(135deg, #CFBAFF 0%, #ffffff 35%, #AE8EFF 65%, #CFBAFF 100%);
  background-origin: border-box;
  background-clip: padding-box, border-box;
  box-shadow: 0 0 16px 4px rgba(0,0,0,0.06);
}
.scinfo__pill + .scinfo__pill { margin-top: 16px; }
.scinfo__bullet {
  flex-shrink: 0;
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ED8936 0%, #ED8936 40%, #8460E5 100%);
  border: 1.5px solid;
  border-image: linear-gradient(135deg, #ffffff, #FBC47D 25%, #AE8EFF 75%, #ffffff) 1;
  box-shadow: 0 2px 6px rgba(237,137,54,0.3), inset 0 1px 0 rgba(255,255,255,0.28);
}
.scinfo__pilltext { font-size: 14px; font-weight: 700; color: #3B1782; }
`;

let _injected = false;

export interface SubasCoinsInfoCardProps {
  benefits?: string[];
  className?: string;
}

export default function SubasCoinsInfoCard({
  benefits = ["Consignaciones más bajas", "Disponibilidad instantánea"],
  className = "",
}: SubasCoinsInfoCardProps): JSX.Element {
  if (typeof document !== "undefined" && !_injected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = STYLES;
      document.head.appendChild(el);
    }
    _injected = true;
  }

  return (
    <>
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: STYLES }} />
      <div className={`scinfo ${className}`.trim()}>
        <div className="scinfo__head">
          <p className="scinfo__eyebrow">Selecciona los</p>
          <p className="scinfo__title">SubasCoins</p>
          <p className="scinfo__sub">que deseas adquirir:</p>
          <span className="scinfo__coin" aria-hidden="true">$</span>
        </div>

        <div className="scinfo__body">
          <p className="scinfo__benefitslabel">Beneficios incluidos</p>
          {benefits.map(function renderPill(b, i) {
            return (
              <div className="scinfo__pill" key={i}>
                <span className="scinfo__bullet" aria-hidden="true" />
                <span className="scinfo__pilltext">{b}</span>
              </div>
            );
          })}
        </div>
      </div>
    </>
  );
}

"use client";

/**
 * AgregarSubascoinsMobile — Bloque de Concorde (Voyager DS) · mobile (420 ancho).
 *
 *   · Header 420×64 con botón hamburguesa (abre SidebarMobile)
 *   · Banner 388×120
 *   · SubasCoinsCardMobile 388×808
 *   · Centro de Ayuda 388×116
 */

import { useState } from "react";
import type { CSSProperties, JSX } from "react";
import AppHeader from "@/concorde/bloques/header/desktop/Header";
import SidebarMobile, { SidebarMenuButton } from "@/concorde/bloques/sidebar/mobile/SidebarMobile";
import SubasCoinsCardMobile from "./SubasCoinsCardMobile";
import { AGREGARSUBASCOINS_MOBILE_WIDTH, AGREGARSUBASCOINS_MOBILE_HEIGHT } from "./dimensions";

export { AGREGARSUBASCOINS_MOBILE_WIDTH, AGREGARSUBASCOINS_MOBILE_HEIGHT } from "./dimensions";

// Banner placeholder gris (mismo estilo que el desktop / demás bloques mobile).
const BANNER: CSSProperties = {
  width: 388,
  boxSizing: "border-box",
  borderRadius: 8,
  background: "#E9EAEC",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: 12,
  fontWeight: 600,
  letterSpacing: "0.08em",
  color: "#9AA1AC",
};

export interface AgregarSubascoinsMobileProps {
  username?: string;
  className?: string;
  /** Alto del marco para previsualizaciones (px). En producción se omite. */
  frameHeight?: number;
}

export default function AgregarSubascoinsMobile({ username = "ZAEX5G", className = "", frameHeight }: AgregarSubascoinsMobileProps): JSX.Element {
  const [menuOpen, setMenuOpen] = useState(false);

  const page = (
    <div
      className={className}
      data-block="agregar-subascoins-mobile"
      style={{
        width: AGREGARSUBASCOINS_MOBILE_WIDTH,
        background: "#ffffff",
        display: "flex",
        flexDirection: "column",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Header 420×64 con hamburguesa */}
      <AppHeader
        width={AGREGARSUBASCOINS_MOBILE_WIDTH}
        username={username}
        compact
        logo={
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <SidebarMenuButton onClick={() => setMenuOpen(true)} expanded={menuOpen} />
            <img src="/logo-preview.png" alt="VMC Subastas" style={{ height: 26, width: "auto", display: "block" }} />
          </div>
        }
      />

      {/* Contenido a 16px de margen */}
      <div style={{ display: "flex", flexDirection: "column", gap: 16, padding: 16 }}>
        {/* Banner superior 388×120 */}
        <div data-slot="banner" style={{ ...BANNER, height: 120 }}>BANNER</div>

        {/* Card «Adquiere SubasCoins» 388×808 */}
        <SubasCoinsCardMobile />

        {/* Centro de ayuda 388×116 */}
        <div data-slot="help-banner" style={{ ...BANNER, height: 116 }}>CENTRO DE AYUDA</div>
      </div>
    </div>
  );

  return (
    <SidebarMobile open={menuOpen} onOpenChange={setMenuOpen} frameHeight={frameHeight}>
      {page}
    </SidebarMobile>
  );
}

/**
 * Dimensiones del bloque AgregarSubascoins · mobile — módulo plano sin "use client".
 *
 * Ancho 420 (contenido 388 con 16px de margen a cada lado). Alto aproximado:
 *   64 (header) + 16 + 120 (banner) + 16 + 808 (card SubasCoins) + 16 + 116 (help) + 16
 */

export const AGREGARSUBASCOINS_MOBILE_WIDTH = 420;
export const AGREGARSUBASCOINS_MOBILE_HEIGHT = 1188;

"use client";

/**
 * SubasCoinsCardMobile — card 388×808 del bloque «Agregar Subascoins» · mobile.
 *
 * Layout vertical (1 columna):
 *   · título «¡Adquiere SubasCoins y disfruta…» (gradiente)
 *   · SubasCoinsInfoCard (card morado + beneficios)
 *   · nota «El valor de >S< 1…»
 *   · AmountOptionGroup (30/50/80/130 + monto personalizado)
 *   · botón «Sigamos» (primary, 200×48) centrado
 *
 * Reutiliza SubasCoinsInfoCard, AmountOptionGroup y Button (los mismos del desktop).
 */

import { useState } from "react";
import type { JSX } from "react";
import AmountOptionGroup, { type AmountSelection } from "@/concorde/components/AmountOptionGroup";
import Button from "@/concorde/components/Button";
import SubasCoinsInfoCard from "@/concorde/bloques/agregar-subascoins/desktop/SubasCoinsInfoCard";

export const SUBASCOINSCARD_MOBILE_WIDTH = 388;
export const SUBASCOINSCARD_MOBILE_HEIGHT = 808;

export interface SubasCoinsCardMobileProps {
  className?: string;
}

export default function SubasCoinsCardMobile({ className = "" }: SubasCoinsCardMobileProps): JSX.Element {
  const [sel, setSel] = useState<AmountSelection>(2); // ">S< 80" preseleccionado

  return (
    <div
      className={className}
      data-slot="subascoins-card-mobile"
      style={{
        boxSizing: "border-box",
        width: SUBASCOINSCARD_MOBILE_WIDTH,
        minHeight: SUBASCOINSCARD_MOBILE_HEIGHT,
        background: "#ffffff",
        borderRadius: 16,
        boxShadow: "0 0 16px 4px rgba(0,0,0,0.08)",
        padding: 20,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 16,
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      {/* Título con gradiente (morado + "SubasCoins" naranja) */}
      <h2
        style={{
          margin: 0,
          width: "100%",
          fontSize: 20,
          lineHeight: "26px",
          fontWeight: 800,
          textAlign: "center",
          backgroundImage: "linear-gradient(135deg, #5F3ED8 0%, #340091 55%, #140046 100%)",
          WebkitBackgroundClip: "text",
          backgroundClip: "text",
          color: "transparent",
          WebkitTextFillColor: "transparent",
        }}
      >
        ¡Adquiere{" "}
        <span
          style={{
            backgroundImage: "linear-gradient(135deg, #FF9639 0%, #EF852E 50%, #BE3D00 100%)",
            WebkitBackgroundClip: "text",
            backgroundClip: "text",
            color: "transparent",
            WebkitTextFillColor: "transparent",
          }}
        >
          SubasCoins
        </span>{" "}
        y disfruta de sus beneficios!
      </h2>

      {/* Card morado SubasCoins + beneficios (392 con max-width:100% → se ajusta a 348) */}
      <SubasCoinsInfoCard />

      {/* Nota del valor */}
      <p style={{ margin: 0, width: "100%", textAlign: "center", fontSize: 13, fontWeight: 600, color: "#ED8936" }}>
        El valor de <strong>{">S<"} 1</strong> es equivalente a US$ 1 (un Dólar Americano).
      </p>

      {/* Opciones de monto (apiladas) */}
      <AmountOptionGroup
        amounts={["30", "50", "80", "130"]}
        allowCustom
        customPlaceholder="210"
        value={sel}
        onChange={setSel}
        className="scm-amounts"
      />

      {/* Sigamos */}
      <Button variant="primary" style={{ width: 200 }}>Sigamos</Button>

      {/* Los AmountOption traen width 254; en mobile los alargamos al ancho de la card */}
      <style dangerouslySetInnerHTML={{ __html: ".scm-amounts{width:100%;align-items:stretch;}.scm-amounts .pamount{width:100%;}" }} />
    </div>
  );
}

﻿"use client";

/**
 * AmountOptionGroup — Generado por Concorde
 *
 * Selector de monto configurable, compuesto con AmountOption:
 *   · `amounts`     → cuántos montos fijos (uno por elemento)
 *   · `allowCustom` → si se muestra la opción personalizada (input editable)
 * Maneja la selección tipo radio (uno activo a la vez). Controlado o no.
 */

import { useId, useState } from "react";
import type { JSX } from "react";
import AmountOption from "@/concorde/components/AmountOption";

export type AmountSelection = number | "custom";

export interface AmountOptionGroupProps {
  /** Montos fijos (solo el número) — la cantidad = length. P.ej. ["80","130","210"] */
  amounts: string[];
  /** Muestra la opción personalizada (input editable) — default false */
  allowCustom?: boolean;
  /** Etiqueta sobre la opción personalizada — default "Ingresa un monto:" */
  customLabel?: string;
  /** Placeholder del número del input — default "0" */
  customPlaceholder?: string;
  /** Prefijo del monto — default ">S<" */
  prefix?: string;
  /** Selección controlada: índice del monto fijo o "custom" */
  value?: AmountSelection;
  /** Selección inicial (no controlado) — default 0 */
  defaultValue?: AmountSelection;
  onChange?: (selected: AmountSelection) => void;
  /** Valor del input personalizado (controlado) */
  customValue?: string;
  onCustomValueChange?: (value: string) => void;
  /** name del grupo radio */
  name?: string;
  className?: string;
}

export default function AmountOptionGroup({
  amounts,
  allowCustom = false,
  customLabel = "Ingresa un monto:",
  customPlaceholder = "0",
  prefix = ">S<",
  value,
  defaultValue = 0,
  onChange,
  customValue,
  onCustomValueChange,
  name,
  className = "",
}: AmountOptionGroupProps): JSX.Element {
  const uid = useId().replace(/:/g, "-");
  const controlled = value !== undefined;
  const [internalSel, setInternalSel] = useState<AmountSelection>(defaultValue);
  const sel = controlled ? value : internalSel;

  const customControlled = customValue !== undefined;
  const [internalCustom, setInternalCustom] = useState("");
  const cval = customControlled ? customValue : internalCustom;

  const groupName = name ?? `amountgroup-${uid}`;

  function select(next: AmountSelection): void {
    if (!controlled) setInternalSel(next);
    onChange?.(next);
  }

  function handleCustomChange(v: string): void {
    if (!customControlled) setInternalCustom(v);
    onCustomValueChange?.(v);
    select("custom");
  }

  return (
    <div role="radiogroup" className={className} style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      {amounts.map(function renderFixed(a, i) {
        return (
          <AmountOption
            key={i}
            name={groupName}
            variant={sel === i ? "selected" : "default"}
            amount={`${prefix} ${a}`}
            onSelect={function pick() { select(i); }}
          />
        );
      })}

      {allowCustom ? (
        <div
          style={{ display: "flex", flexDirection: "column", gap: 8 }}
          onFocusCapture={function focusCustom() { select("custom"); }}
        >
          <span style={{ fontSize: 11, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "#94A3B8", fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', sans-serif)" }}>
            {customLabel}
          </span>
          <AmountOption
            variant="input"
            name={groupName}
            prefix={prefix}
            placeholder={customPlaceholder}
            value={cval}
            selected={sel === "custom"}
            onValueChange={handleCustomChange}
          />
        </div>
      ) : null}
    </div>
  );
}

"use client";

/**
 * AmountOption — Generado por Concorde
 * Fuente: Figma VOYAGER · "AmountOption" (3032:13035 default · 13029 selected · 13044 input)
 *
 * Opción de monto tipo radio (pill 254×48, radio 24) con un círculo a la
 * izquierda y el monto a la derecha. 3 variantes:
 *   · default  → blanco, borde gradiente sutil, radio gris, monto morado #3B1782
 *   · selected → relleno gradiente morado (#8460E5→#3B1782), borde gradiente,
 *                radio relleno blanco, monto blanco
 *   · input    → blanco, radio gris, campo editable con placeholder gris #D1D5DC
 * Sombra 0 0 16px 4px rgba(0,0,0,0.1). Controlado o no controlado.
 */

import { useId } from "react";
import type { JSX, ReactNode } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────

export type AmountOptionVariant = "default" | "selected" | "input";

export interface AmountOptionProps {
  /** Apariencia/estado (default "default") */
  variant?: AmountOptionVariant;
  /** Monto fijo (modo default/selected) — p.ej. ">S< 80" */
  amount?: ReactNode;
  /** Valor del campo (modo input, controlado) */
  value?: string;
  /** Valor inicial (modo input, no controlado) */
  defaultValue?: string;
